const express = require('express');
const bodyParser = require('body-parser');
const crypto = require('crypto');
const url = require('url');

const app = express();
app.use(bodyParser.urlencoded({ extended: true }));

// In-memory storage for clients and tokens
const clients = {};
const codes = {};
const tokens = {};

// Register a client with the server
function registerClient(clientId, redirectUri) {
  if (!clients[clientId]) {
    clients[clientId] = { redirectUri };
  }
}

// Generate an authorization code
function generateCode() {
  return crypto.randomBytes(32).toString('hex');
}

// Exchange an authorization code for an access token
function exchangeCodeForToken(code, clientId) {
  if (codes[code] && codes[code].clientId === clientId) {
    const accessToken = crypto.randomBytes(32).toString('hex');
    tokens[accessToken] = { clientId };
    delete codes[code];
    return accessToken;
  }
  throw new Error('Invalid code');
}

// Authorization endpoint
app.get('/authorize', (req, res) => {
  const { client_id, redirect_uri, state } = req.query;

  if (!clients[client_id]) {
    return res.status(400).send('Client not registered');
  }

  const authorizationCode = generateCode();
  codes[authorizationCode] = { clientId: client_id };

  const authorizeUrl = `${redirect_uri}?code=${authorizationCode}&state=${state}`;
  res.redirect(authorizeUrl);
});

// Token endpoint
app.post('/token', (req, res) => {
  const { code, client_id } = req.body;

  try {
    const accessToken = exchangeCodeForToken(code, client_id);
    res.json({ access_token: accessToken });
  } catch (error) {
    res.status(400).send(error.message);
  }
});

// Register clients
